+
+test "extractJsonField: handles escaped quotes" {
+    const val = Tunnel.extractJsonField("{\"msg\":\"say \\\"hello\\\"\"}", "msg");
+    try std.testing.expectEqualStrings("say \\\"hello\\\"", val.?);
